// CLX Signal Intelligence v1 — Fan out one item per raw signal
// Fetch Unprocessed Signals returns an array in a single item; we
// split it into N items so downstream per-signal processing works.
// Also passes verticals context alongside (same reference every
// iteration — Claude prompt builder reads it).

const signalsRaw = $('Fetch Unprocessed Signals').first().json;
const verticalsRaw = $('Fetch Active Verticals').first().json;

const signals = Array.isArray(signalsRaw) ? signalsRaw : (signalsRaw && signalsRaw.id ? [signalsRaw] : []);
const verticals = Array.isArray(verticalsRaw) ? verticalsRaw : [];

if (signals.length === 0) {
  return [{ json: { _empty: true, reason: 'no_unprocessed_signals' } }];
}

return signals.map(s => ({ json: { signal: s, verticals } }));

// CLX Signal Intelligence v1 — Build Claude prompt
// Constructs the system + user prompt Claude receives for a single
// raw signal. Verticals list comes from the same item (attached in
// Fan Out). Claude returns JSON that matches the
// market_signals_processed schema.

const signal = $json.signal;
const verticals = Array.isArray($json.verticals) ? $json.verticals : [];
const today = new Date().toISOString().split('T')[0];

const verticalList = verticals.map(v => {
  const name = v.vertical || v.niche_name || 'unknown';
  const targets = v.lead_target_type || 'mixed';
  return `${name} (targets: ${targets})`;
}).join(', ');

const systemPrompt = [
  'You are a market intelligence analyst for Crystallux, a Canadian B2B lead-generation platform serving these verticals: ' + (verticals.map(v => v.vertical || v.niche_name).filter(Boolean).join(', ') || 'insurance_broker') + '.',
  '',
  'Your job: analyse a signal (news article, weather alert, economic indicator, regulatory filing) and determine which verticals it affects, how, and with what urgency.',
  '',
  'Output strictly as valid JSON only. No markdown, no preamble, no explanation outside the JSON structure.',
  '',
  'Schema:',
  '{',
  '  "signal_type": "natural_disaster|economic|regulatory|seasonal|news_event|trend|political|technological",',
  '  "headline": "1-line summary under 100 chars",',
  '  "summary": "2-3 sentence analysis explaining why this signal matters",',
  '  "affected_regions": ["ON", "BC"],',
  '  "affected_verticals": [',
  '    {',
  '      "vertical": "insurance_broker",',
  '      "impact": "very_high|high|moderate|low|negative",',
  '      "outreach_multiplier": 1.5,',
  '      "messaging_angle": "How to frame outreach given this signal. Peer-advisor tone. 1-2 sentences.",',
  '      "suggested_pain_signals": ["specific pains this signal creates — strings"],',
  '      "urgency_window_hours": 168',
  '    }',
  '  ],',
  '  "decay_time_days": 7,',
  '  "confidence": "high|medium|low"',
  '}',
  '',
  'Rules:',
  '- Do NOT hallucinate. If the signal is irrelevant to any vertical, return empty affected_verticals array and confidence: low.',
  '- Be conservative with outreach_multiplier. 1.0 = no change. 2.0 = double outreach. 3.0 = major spike. Reserve 4.0+ for rare existential events.',
  '- messaging_angle must be specific to Canadian context and peer-advisor tone (short, direct, no jargon).',
  '- Only include verticals in the active list provided. Reject unknown verticals.',
  '- Consider regulatory signals (FSRA, CRTC, RIBO, RCDSO) carefully — they can be HIGH impact for specific verticals.',
  '- Seasonal signals should have 60-90 day decay, not 7.',
  '- If input looks like an aggregated daily indicator (Bank of Canada observations with minor day-over-day change), default to confidence: low and multiplier near 1.0.'
].join('\n');

const userPrompt = [
  'Signal to analyze:',
  'Source: ' + signal.source,
  'Date: ' + signal.fetched_at,
  'Raw data: ' + JSON.stringify(signal.raw_payload || {}, null, 2).slice(0, 3000),
  '',
  'Current date: ' + today,
  'Active verticals available: ' + (verticalList || 'insurance_broker (targets: mixed)'),
  '',
  'Analyse and return JSON.'
].join('\n');

return { json: {
  raw_signal_id: signal.id,
  source: signal.source,
  raw_url: signal.raw_url || null,
  system_prompt: systemPrompt,
  user_prompt: userPrompt
} };

// CLX Signal Intelligence v1 — Parse Claude response
// Extracts JSON from Claude's text response, strips markdown fences,
// validates required structure. Failure modes: parse error,
// empty/unexpected response, missing required keys → mark as
// needs_review and route to the scan_errors path.

const resp = $input.item.json || {};
const ctx = $('Build Claude Prompt').first().json;

let textOut = null;
try {
  textOut = (resp.content && resp.content[0] && resp.content[0].text) || null;
} catch (e) { textOut = null; }

const tokens = (resp.usage && (resp.usage.input_tokens + resp.usage.output_tokens)) || 0;

if (!textOut) {
  return { json: {
    raw_signal_id: ctx.raw_signal_id,
    needs_review: true,
    parse_error: 'no_text_in_response',
    raw_response: JSON.stringify(resp).slice(0, 500)
  } };
}

const cleaned = String(textOut).replace(/```json|```/g, '').trim();
let parsed = null;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  return { json: {
    raw_signal_id: ctx.raw_signal_id,
    needs_review: true,
    parse_error: e.message,
    raw_text: cleaned.slice(0, 500)
  } };
}

// Schema validation
if (!parsed.signal_type || !Array.isArray(parsed.affected_verticals)) {
  return { json: {
    raw_signal_id: ctx.raw_signal_id,
    needs_review: true,
    parse_error: 'missing_required_fields',
    raw_text: cleaned.slice(0, 500)
  } };
}

// Clamp multipliers 0.1 .. 5.0 and impact values
const validImpacts = ['very_high','high','moderate','low','negative'];
const validSignalTypes = ['natural_disaster','economic','regulatory','seasonal','news_event','trend','political','technological'];
const validConfidence = ['high','medium','low'];

if (!validSignalTypes.includes(parsed.signal_type)) {
  parsed.signal_type = 'news_event';
}
if (!validConfidence.includes(parsed.confidence)) {
  parsed.confidence = 'low';
}
parsed.affected_verticals = (parsed.affected_verticals || []).map(v => ({
  vertical: v.vertical,
  impact: validImpacts.includes(v.impact) ? v.impact : 'moderate',
  outreach_multiplier: Math.min(Math.max(Number(v.outreach_multiplier) || 1.0, 0.1), 5.0),
  messaging_angle: v.messaging_angle || '',
  suggested_pain_signals: Array.isArray(v.suggested_pain_signals) ? v.suggested_pain_signals : [],
  urgency_window_hours: Number(v.urgency_window_hours) || 168
}));

return { json: {
  raw_signal_id: ctx.raw_signal_id,
  signal_type: parsed.signal_type,
  headline: (parsed.headline || '(no headline)').slice(0, 500),
  summary: parsed.summary || null,
  affected_regions: Array.isArray(parsed.affected_regions) ? parsed.affected_regions : [],
  affected_verticals: parsed.affected_verticals,
  messaging_angle: (parsed.affected_verticals[0] && parsed.affected_verticals[0].messaging_angle) || null,
  suggested_pain_signals: (parsed.affected_verticals[0] && parsed.affected_verticals[0].suggested_pain_signals) || [],
  decay_time_days: Math.min(Math.max(Number(parsed.decay_time_days) || 30, 1), 180),
  confidence: parsed.confidence,
  source_url: ctx.raw_url,
  claude_model_used: 'claude-sonnet-4-5-20250929',
  tokens_consumed: tokens,
  needs_review: false
} };

// CLX Signal Intelligence v1 — Prep processed row
// Builds the INSERT body for market_signals_processed. Computes
// expires_at = now + decay_time_days. Flips active=false for
// low-confidence signals with no vertical impact (avoids routing on
// noise).

const a = $json;
const now = new Date();
const expiresAt = new Date(now.getTime() + (a.decay_time_days || 30) * 24 * 60 * 60 * 1000);

const noImpact = !Array.isArray(a.affected_verticals) || a.affected_verticals.length === 0;
const active = a.confidence !== 'low' && !noImpact;

const hasVeryHighImpact = Array.isArray(a.affected_verticals)
  && a.affected_verticals.some(v => v.impact === 'very_high');

return { json: {
  rpc_body: {
    raw_signal_id: a.raw_signal_id,
    signal_type: a.signal_type,
    headline: a.headline,
    summary: a.summary,
    affected_regions: a.affected_regions || [],
    affected_verticals: a.affected_verticals || [],
    messaging_angle: a.messaging_angle,
    suggested_pain_signals: a.suggested_pain_signals || [],
    decay_time_days: a.decay_time_days || 30,
    confidence: a.confidence,
    active,
    expires_at: expiresAt.toISOString(),
    source_url: a.source_url,
    claude_model_used: a.claude_model_used,
    tokens_consumed: a.tokens_consumed || 0
  },
  raw_signal_id: a.raw_signal_id,
  hasVeryHighImpact,
  tokens_consumed: a.tokens_consumed || 0
} };
